const http = require('http');
const fs = require('fs');
const path = require('path');
const { URL } = require('url');

function enhanceResponse(res) {
  res.status = function (code) {
    res.statusCode = code;
    return res;
  };

  res.json = function (data) {
    res.setHeader('Content-Type', 'application/json; charset=utf-8');
    res.end(JSON.stringify(data));
  };

  res.send = function (data) {
    if (typeof data === 'object') {
      return res.json(data);
    }
    res.end(data);
  };

  res.sendFile = function (filePath) {
    const ext = path.extname(filePath).toLowerCase();
    const contentTypes = {
      '.html': 'text/html; charset=utf-8',
      '.css': 'text/css; charset=utf-8',
      '.js': 'application/javascript; charset=utf-8',
      '.json': 'application/json; charset=utf-8'
    };

    fs.readFile(filePath, (error, data) => {
      if (error) {
        res.statusCode = 404;
        res.end('File not found');
        return;
      }
      res.setHeader('Content-Type', contentTypes[ext] || 'application/octet-stream');
      res.end(data);
    });
  };
}

function matchPath(routePath, requestPath) {
  if (routePath === requestPath) {
    return { matched: true, params: {} };
  }

  const routeParts = routePath.split('/').filter(Boolean);
  const requestParts = requestPath.split('/').filter(Boolean);
  if (routeParts.length !== requestParts.length) {
    return { matched: false, params: {} };
  }

  const params = {};
  for (let index = 0; index < routeParts.length; index += 1) {
    const routePart = routeParts[index];
    const requestPart = requestParts[index];
    if (routePart.startsWith(':')) {
      params[routePart.slice(1)] = requestPart;
      continue;
    }
    if (routePart !== requestPart) {
      return { matched: false, params: {} };
    }
  }

  return { matched: true, params };
}

function createApp() {
  const middlewares = [];
  const routes = [];

  const app = function () {};

  app.use = function (basePath, handler) {
    if (typeof basePath === 'function') {
      middlewares.push({ basePath: '/', handler: basePath });
      return;
    }

    if (handler && handler.__isRouter) {
      handler.routes.forEach((route) => {
        routes.push({
          method: route.method,
          path: `${basePath}${route.path}`.replace(/\/+/g, '/'),
          handler: route.handler
        });
      });
      return;
    }

    middlewares.push({ basePath, handler });
  };

  ['GET', 'POST', 'PUT', 'DELETE'].forEach((method) => {
    app[method.toLowerCase()] = function (routePath, handler) {
      routes.push({ method, path: routePath, handler });
    };
  });

  app.listen = function (port, callback) {
    const server = http.createServer((req, res) => {
      enhanceResponse(res);
      const parsedUrl = new URL(req.url, `http://${req.headers.host}`);
      req.path = parsedUrl.pathname;
      req.query = Object.fromEntries(parsedUrl.searchParams.entries());
      req.params = {};
      req.body = {};

      let bodyBuffer = '';
      req.on('data', (chunk) => {
        bodyBuffer += chunk;
      });

      req.on('end', () => {
        req.rawBody = bodyBuffer;

        let middlewareIndex = 0;
        const runMiddleware = () => {
          if (middlewareIndex >= middlewares.length) {
            runRoute();
            return;
          }

          const middleware = middlewares[middlewareIndex];
          middlewareIndex += 1;

          if (!req.path.startsWith(middleware.basePath)) {
            runMiddleware();
            return;
          }

          middleware.handler(req, res, runMiddleware);
        };

        const runRoute = () => {
          const route = routes.find((item) => {
            if (item.method !== req.method) return false;
            const result = matchPath(item.path, req.path);
            if (!result.matched) return false;
            req.params = result.params;
            return true;
          });

          if (!route) {
            res.statusCode = 404;
            res.end('Not found');
            return;
          }

          route.handler(req, res);
        };

        runMiddleware();
      });
    });

    server.listen(port, callback);
    return server;
  };

  app.__isRouter = true;
  app.routes = routes;
  return app;
}

function Router() {
  return createApp();
}

function json() {
  return function (req, res, next) {
    if ((req.headers['content-type'] || '').includes('application/json') && req.rawBody) {
      try {
        req.body = JSON.parse(req.rawBody);
      } catch (error) {
        res.statusCode = 400;
        res.end('Invalid JSON');
        return;
      }
    }
    next();
  };
}

function urlencoded() {
  return function (req, res, next) {
    if ((req.headers['content-type'] || '').includes('application/x-www-form-urlencoded') && req.rawBody) {
      req.body = Object.fromEntries(new URLSearchParams(req.rawBody).entries());
    }
    next();
  };
}

function staticMiddleware(rootDir) {
  return function (req, res, next) {
    const filePath = path.join(rootDir, req.path === '/' ? '/index.html' : req.path);
    if (!filePath.startsWith(rootDir)) {
      next();
      return;
    }
    fs.stat(filePath, (error, stats) => {
      if (error || !stats.isFile()) {
        next();
        return;
      }
      res.sendFile(filePath);
    });
  };
}

createApp.Router = Router;
createApp.json = json;
createApp.urlencoded = urlencoded;
createApp.static = staticMiddleware;
module.exports = createApp;
